import React, { useState, useEffect } from "react";
import io from "socket.io-client";

const socket = io("http://localhost:5000");

function App() {
  const [username, setUsername] = useState("");
  const [message, setMessage] = useState("");
  const [messageList, setMessageList] = useState([]);
  const [showChat, setShowChat] = useState(false);

  const sendMessage = () => {
    if (message !== "") {
      const messageData = {
        author: username,
        message: message,
        time: new Date().toLocaleTimeString(),
      };

      socket.emit("send_message", messageData);
      setMessage("");
    }
  };

  useEffect(() => {
    // Load old messages
    socket.on("load_messages", (data) => {
      setMessageList(data);
    });

    // Receive new messages
    const handleMessage = (data) => {
      setMessageList((list) => [...list, data]);
    };

    socket.on("receive_message", handleMessage);

    return () => {
      socket.off("receive_message", handleMessage);
    };
  }, []);

  return (
    <div style={{ textAlign: "center", marginTop: "50px" }}>
      {!showChat ? (
        <div>
          <h2>Enter Username</h2>
          <input
            placeholder="Enter name..."
            onChange={(e) => setUsername(e.target.value)}
          />
          <button onClick={() => setShowChat(true)}>Join Chat</button>
        </div>
      ) : (
        <div>
          <h2>Chat App 💬</h2>

          <div style={{
            width: "300px",
            margin: "auto",
            border: "1px solid black",
            padding: "10px",
            height: "300px",
            overflowY: "scroll"
          }}>
            {messageList.map((msg, index) => (
              <div
                key={index}
                style={{
                  textAlign: msg.author === username ? "right" : "left",
                  margin: "5px"
                }}
              >
                <div
                  style={{
                    display: "inline-block",
                    padding: "8px",
                    borderRadius: "10px",
                    backgroundColor: msg.author === username ? "#4CAF50" : "#eee",
                    color: msg.author === username ? "white" : "black"
                  }}
                >
                  <strong>{msg.author}</strong><br />
                  {msg.message}
                  <div style={{ fontSize: "10px" }}>{msg.time}</div>
                </div>
              </div>
            ))}
          </div>

          <input
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type message..."
          />
          <button onClick={sendMessage}>Send</button>
        </div>
      )}
    </div>
  );
}

export default App;
